169	}
170	/** Fire `run()` and return every trace event of the headless work it kicked off. */
171	async function fireAndTrace(pod, run, { settleMs = 240_000, quietMs = 20_000 } = {}) {
172	  const before = new Set(await sessionIds(pod));
173	  const res = await run().catch((e) => ({ error: String(e) }));
174	  const t0 = now();
175	  let seen = new Set();
176	  let lastGrowth = now();
177	  let events = [];
178	  while (now() - t0 < settleMs) {
179	    await sleep(5_000);
180	    const ids = (await sessionIds(pod)).filter((i) => !before.has(i));
181	    for (const i of ids) seen.add(i);
182	    const drained = await drainSessions(pod, [...seen]);
183	    if (drained.length > events.length) lastGrowth = now();
184	    events = drained;
185	    const idle = await pod.req('GET', '/api/sessions').catch(() => ({ sessions: [] }));
186	    const busy = (idle.sessions ?? []).some((s) => seen.has(s.sessionId) && s.status !== 'idle');
187	    if (events.length && !busy && now() - lastGrowth > quietMs) break;
188	  }
189	  return { res, events, sessions: [...seen] };
190	}
